import litellm

# 設定多個 API key，自動輪流使用
litellm.api_key = [
    'sk-ant-key1',
    'sk-ant-key2', 
    'sk-ant-key3'
]

# 或者用 router（更強大）
from litellm import Router

router = Router(
    model_list=[
        {
            'model_name': 'claude-fast',
            'litellm_params': {
                'model': 'claude-sonnet-4-6',
                'api_key': 'sk-ant-key1',
                'rpm': 100  # 每分鐘最多 100 次
            }
        },
        {
            'model_name': 'claude-fast',
            'litellm_params': {
                'model': 'claude-sonnet-4-6',
                'api_key': 'sk-ant-key2',
                'rpm': 100
            }
        },
        {
            'model_name': 'claude-fast',
            'litellm_params': {
                'model': 'gpt-4o',
                'api_key': 'sk-openai-key',
                'rpm': 500
            }
        }
    ],
    routing_strategy='least-busy'  # 選最空閒嘅
)

response = await router.acompletion(
    model='claude-fast',
    messages=[{'role': 'user', 'content': '你好'}]
)
